import { useState, useRef } from "react";

export default function UploadPage() {
  const [file, setFile] = useState(null);
  const [error, setError] = useState(null);
  const inputRef = useRef();

  const handleFile = (f) => {
    if (!f || f.type !== "application/pdf") return setError("PDF files only");
    if (f.size > 10 * 1024 * 1024) return setError("Max file size is 10 MB");
    setError(null);
    setFile(f);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    handleFile(e.dataTransfer.files[0]);
  };

  const handleParse = async () => {
    // TODO: extract text with PDF.js, then call Claude API
  };

  return (
    <div>
      {/* Nav */}
      {/* Drop zone — onDrop={handleDrop} onDragOver={e => e.preventDefault()} */}
      {/* Hidden <input type="file" ref={inputRef} accept=".pdf" onChange={...} /> */}
      {/* File pill — shown when file !== null */}
      {/* Parse button — onClick={handleParse} */}
    </div>
  );
}
